use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

type ProductId = String;
type Quantity = u32;

#[derive(Debug, PartialEq, Clone)]
pub enum InventoryError {
    ProductNotFound,
    InsufficientStock(u32),
    UpdateFailed, // Represents a mutex poisoning or other internal error
}

pub fn initialize_inventory(
    initial_stock: HashMap<ProductId, Quantity>,
) -> Arc<Mutex<HashMap<ProductId, Quantity>>> {
    Arc::new(Mutex::new(initial_stock))
}

pub fn update_inventory(
    inventory: Arc<Mutex<HashMap<ProductId, Quantity>>>,
    product_id: ProductId,
    quantity_to_decrement: Quantity,
) -> Result<(), InventoryError> {
    let mut inv_guard = inventory.lock().map_err(|_| InventoryError::UpdateFailed)?;

    match inv_guard.get_mut(&product_id) {
        Some(current_stock) => {
            if *current_stock >= quantity_to_decrement {
                *current_stock -= quantity_to_decrement;
                Ok(())
            } else {
                Err(InventoryError::InsufficientStock(*current_stock))
            }
        }
        None => Err(InventoryError::ProductNotFound),
    }
}

